module width_8to16(
    input clk,
    input rst_n,
    input valid_in,
    input [7:0] data_in,
    output valid_out,
    output reg [15:0] data_out
);

reg [15:0] buffer;
reg [1:0] state;
reg [2:0] count;

assign valid_out = (count == 3'd2);

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        buffer <= 0;
        state <= 0;
        count <= 0;
        data_out <= 0;
    end else begin
        case (state)
            2'b00: begin
                if (valid_in) begin
                    buffer[15:8] <= data_in;
                    state <= 2'b01;
                    count <= count + 1;
                end
            end
            2'b01: begin
                if (valid_in) begin
                    buffer[7:0] <= data_in;
                    state <= 2'b10;
                    count <= count + 1;
                end
            end
            2'b10: begin
                if (valid_in) begin
                    data_out <= buffer;
                    buffer <= 0;
                    state <= 2'b00;
                    count <= 0;
                end
            end
        endcase
    end
end

endmodule
